import React, {
  useCallback,
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
} from 'react';
import './Projects.css';

const PROJECTS = {
  client: [
    { id: 1, driveId: '1kLu1xB-nZ1jgciDCb1dk3HNjhQozzrXQ' },
    { id: 2, driveId: '1TKG_d0NyaAFVMc2LwQOmRQfj6XhKX_C8' },
    { id: 3, driveId: '1R-jHt3l6rJwiYjAgXnZdyn-u5jlky6Z5' },
    { id: 4, driveId: '1TuUcvxbY_VEP_SHWnZ1by2MLNT4AJGrZ' },
    { id: 5, driveId: '1xebUY4lRZGq-R4EfRlMcGNd8KY-SnHhE' },
    { id: 6, driveId: '1KC_0YOuKaEZoAeZPmdNKPV7JC28pJIce' },
    { id: 7, driveId: '1_8tsLwTUPPjwcJEYtpuMjPbH0GOlOsZX' },
    { id: 8, driveId: '1aBefknyW5kPAkexZs5-3JsS2o3XJ8BY0' },
  ],
  personal: [],
  freelance: [],
};

const TABS = [
  { key: 'client', label: 'Client Work' },
  { key: 'personal', label: 'Personal' },
  { key: 'freelance', label: 'Freelance' },
];

function ThumbVisual() {
  return (
    <div className="thumb-visual">
      <div className="thumb-dots" aria-hidden="true">
        <span className="dot dot-rec" />
        <span className="dot dot-blue" />
      </div>
      <div className="thumb-center" aria-hidden="true">
        <span className="thumb-rule" />
        <span className="thumb-client">CLIENT</span>
        <span className="thumb-work">WORK</span>
        <span className="thumb-rule" />
      </div>
      <span className="thumb-play" aria-hidden="true">
        {'\u25B6  PLAY'}
      </span>
    </div>
  );
}

function ProjectFrame({ project, className }) {
  if (!project) return null;

  return (
    <div className={className}>
      <iframe
        className="modal-iframe"
        src={`https://drive.google.com/file/d/${project.driveId}/preview`}
        title={`Project ${project.id}`}
        sandbox="allow-same-origin allow-scripts allow-popups allow-forms"
        allow="autoplay; encrypted-media"
        allowFullScreen={true}
      />
    </div>
  );
}

export default function Projects() {
  const [activeTab, setActiveTab] = useState('client');
  const [displayTab, setDisplayTab] = useState('client');
  const [tabTransition, setTabTransition] = useState(false);
  const [gridEntering, setGridEntering] = useState(false);
  const [pillStyle, setPillStyle] = useState({});
  const [pillTransitionEnabled, setPillTransitionEnabled] = useState(false);
  const [pillBouncing, setPillBouncing] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [modalIndex, setModalIndex] = useState(0);
  const [modalTransition, setModalTransition] = useState('idle');
  const [switchDirection, setSwitchDirection] = useState('right');
  const [switchPhase, setSwitchPhase] = useState('idle');
  const [switchingProject, setSwitchingProject] = useState(null);
  const [sourceIndex, setSourceIndex] = useState(null);

  const tabRefs = useRef({});
  const tabContainerRef = useRef(null);
  const pillTrackRef = useRef({ x: 0, width: 0 });
  const pillRafRef = useRef(null);
  const timeoutsRef = useRef([]);

  const currentProjects = PROJECTS[displayTab] || [];
  const currentProject = currentProjects[modalIndex] || null;

  const clearAllTimeouts = useCallback(() => {
    timeoutsRef.current.forEach((timeoutId) => clearTimeout(timeoutId));
    timeoutsRef.current = [];
  }, []);

  const queueTimeout = useCallback((callback, delay) => {
    const timeoutId = setTimeout(callback, delay);
    timeoutsRef.current.push(timeoutId);
  }, []);

  const cancelPillFrame = () => {
    if (pillRafRef.current) {
      cancelAnimationFrame(pillRafRef.current);
      pillRafRef.current = null;
    }
  };

  const measurePill = useCallback(
    (disableTransition = false) => {
      const container = tabContainerRef.current;
      const activeEl = tabRefs.current[activeTab];
      if (!container || !activeEl) return;

      const cRect = container.getBoundingClientRect();
      const aRect = activeEl.getBoundingClientRect();
      const x = aRect.left - cRect.left;
      const width = aRect.width;

      pillTrackRef.current = { x, width };

      setPillStyle({
        width: `${width}px`,
        transform: `translateX(${x}px)`,
        transition: disableTransition ? 'none' : undefined,
      });

      cancelPillFrame();
      pillRafRef.current = requestAnimationFrame(() => {
        setPillStyle({
          width: `${width}px`,
          transform: `translateX(${x}px)`,
          transition: undefined,
        });
        setPillTransitionEnabled(true);
      });
    },
    [activeTab],
  );

  const startModalEnter = useCallback(
    (index) => {
      if (!currentProjects[index]) return;
      clearAllTimeouts();
      setSourceIndex(index);
      setModalIndex(index);
      setModalOpen(true);
      setModalTransition('entering');
      setSwitchPhase('idle');
      setSwitchingProject(null);
      queueTimeout(() => {
        setModalTransition('active');
        setSourceIndex(null);
      }, 520);
    },
    [clearAllTimeouts, currentProjects, queueTimeout],
  );

  const closeModal = useCallback(
    (afterClose) => {
      if (!modalOpen) {
        if (afterClose) afterClose();
        return;
      }

      clearAllTimeouts();
      setModalTransition('exiting');
      setSwitchPhase('idle');
      setSwitchingProject(null);
      setSourceIndex(null);
      queueTimeout(() => {
        setModalOpen(false);
        setModalTransition('idle');
        if (afterClose) afterClose();
      }, 260);
    },
    [clearAllTimeouts, modalOpen, queueTimeout],
  );

  const runTabTransition = useCallback(
    (tabKey) => {
      clearAllTimeouts();
      setModalIndex(0);
      setTabTransition(true);
      setGridEntering(false);

      queueTimeout(() => {
        setDisplayTab(tabKey);
        setActiveTab(tabKey);
      }, 200);

      queueTimeout(() => {
        setTabTransition(false);
        setGridEntering(true);
      }, 220);

      queueTimeout(() => {
        setGridEntering(false);
      }, 560);
    },
    [clearAllTimeouts, queueTimeout],
  );

  const switchProject = useCallback(
    (direction) => {
      if (!modalOpen || modalTransition === 'switching') return;

      const delta = direction === 'right' ? 1 : -1;
      const nextIndex = modalIndex + delta;
      if (nextIndex < 0 || nextIndex >= currentProjects.length) return;

      clearAllTimeouts();
      setSwitchDirection(direction);
      setSwitchingProject(currentProject);
      setSwitchPhase('out');
      setModalTransition('switching');

      queueTimeout(() => {
        setModalIndex(nextIndex);
        setSwitchPhase('in');
      }, 150);

      queueTimeout(() => {
        setSwitchPhase('idle');
        setSwitchingProject(null);
        setModalTransition('active');
      }, 500);
    },
    [
      clearAllTimeouts,
      currentProject,
      currentProjects.length,
      modalIndex,
      modalOpen,
      modalTransition,
      queueTimeout,
    ],
  );

  const handleTabChange = useCallback(
    (tabKey) => {
      if (tabKey === activeTab) return;
      setPillBouncing(false);
      queueTimeout(() => {
        setPillBouncing(true);
      }, 0);

      if (modalOpen) {
        closeModal(() => runTabTransition(tabKey));
        return;
      }

      runTabTransition(tabKey);
    },
    [activeTab, closeModal, modalOpen, queueTimeout, runTabTransition],
  );

  useLayoutEffect(() => {
    measurePill(!pillTransitionEnabled);

    const handleResize = () => {
      measurePill(true);
    };

    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
      cancelPillFrame();
    };
  }, [measurePill, pillTransitionEnabled]);

  useEffect(() => {
    if (!pillBouncing) return;
    queueTimeout(() => {
      setPillBouncing(false);
    }, 360);
  }, [pillBouncing, queueTimeout]);

  useEffect(() => {
    if (!modalOpen) return;

    const onKeyDown = (event) => {
      if (event.key === 'Escape') {
        closeModal();
      }
      if (event.key === 'ArrowRight') {
        switchProject('right');
      }
      if (event.key === 'ArrowLeft') {
        switchProject('left');
      }
    };

    window.addEventListener('keydown', onKeyDown);
    return () => {
      window.removeEventListener('keydown', onKeyDown);
    };
  }, [closeModal, modalOpen, switchProject]);

  useEffect(() => {
    document.body.style.overflow = modalOpen ? 'hidden' : '';
    return () => {
      document.body.style.overflow = '';
    };
  }, [modalOpen]);

  useEffect(() => {
    return () => {
      clearAllTimeouts();
      cancelPillFrame();
      document.body.style.overflow = '';
    };
  }, [clearAllTimeouts]);

  return (
    <section className="projects-page">
      <div className="projects-tabs-shell">
        <div
          ref={tabContainerRef}
          className="projects-tabs"
          role="tablist"
          aria-label="Project categories"
        >
          <div className="projects-tab-pill-track" style={pillStyle} aria-hidden="true">
            <div
              className={`projects-tab-pill ${pillBouncing ? 'is-bouncing' : ''}`}
            />
          </div>
          {TABS.map((tab) => (
            <button
              key={tab.key}
              ref={(el) => {
                tabRefs.current[tab.key] = el;
              }}
              type="button"
              className={`projects-tab ${activeTab === tab.key ? 'is-active' : ''}`}
              onClick={() => handleTabChange(tab.key)}
            >
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      <div
        className={`projects-grid-wrapper ${tabTransition ? 'grid-dissolve-out' : ''} ${gridEntering ? 'grid-dissolve-in' : ''} ${modalTransition === 'entering' ? 'modal-opening' : ''}`}
      >
        <div className="grid-glow" aria-hidden="true" />
        {currentProjects.length > 0 ? (
          <div className="projects-grid">
            {currentProjects.map((project, index) => {
              const isActive = modalOpen && index === modalIndex;
              const isSource = modalTransition === 'entering' && index === sourceIndex;
              const isDimmed = modalTransition === 'entering' && index !== sourceIndex;
              return (
                <button
                  key={project.id}
                  type="button"
                  className={`thumb-card ${isActive ? 'is-active' : ''} ${isSource ? 'is-source-opening' : ''} ${isDimmed ? 'is-dimmed' : ''}`}
                  style={{ '--card-delay': `${(index % 8) * 40}ms` }}
                  onClick={() => startModalEnter(index)}
                >
                  <ThumbVisual />
                  {isActive && <span className="thumb-top-accent" aria-hidden="true" />}
                </button>
              );
            })}
          </div>
        ) : (
          <div className="projects-empty" aria-live="polite">
            <svg viewBox="0 0 24 24" aria-hidden="true">
              <path d="M3 3h7v7H3zM14 3h7v7h-7zM3 14h7v7H3zM17.5 14v2.5H20V19h-2.5v2.5H15V19h-2.5v-2.5H15V14z" />
            </svg>
            <p>Projects coming soon</p>
          </div>
        )}
      </div>

      {modalOpen && currentProject && (
        <>
          <div
            className={`projects-modal-backdrop ${
              modalTransition === 'entering' ||
              modalTransition === 'active' ||
              modalTransition === 'switching'
                ? 'is-visible'
                : ''
            } ${modalTransition === 'exiting' ? 'is-exiting' : ''}`}
            onClick={() => closeModal()}
            aria-hidden="true"
          />

          <button
            type="button"
            className="modal-close"
            onClick={() => closeModal()}
          >
            {'\u2715  Close'}
          </button>

          <button
            type="button"
            className="modal-nav modal-nav-left"
            onClick={() => switchProject('left')}
            disabled={modalIndex === 0 || modalTransition === 'switching'}
            aria-label="Previous project"
          >
            <svg viewBox="0 0 24 24" aria-hidden="true">
              <path d="M14.5 6.5 9 12l5.5 5.5" />
            </svg>
          </button>

          <button
            type="button"
            className="modal-nav modal-nav-right"
            onClick={() => switchProject('right')}
            disabled={
              modalIndex === currentProjects.length - 1 ||
              modalTransition === 'switching'
            }
            aria-label="Next project"
          >
            <svg viewBox="0 0 24 24" aria-hidden="true">
              <path d="M9.5 6.5 15 12l-5.5 5.5" />
            </svg>
          </button>

          <div
            className={`projects-modal-content ${
              modalTransition === 'entering' ||
              modalTransition === 'active' ||
              modalTransition === 'switching'
                ? 'is-visible'
                : ''
            } ${modalTransition === 'exiting' ? 'is-exiting' : ''}`}
          >
            <div className="modal-video-shell">
              {modalTransition === 'switching' && switchingProject ? (
                <>
                  <ProjectFrame
                    project={switchingProject}
                    className={`modal-frame-layer is-out dir-${switchDirection} ${switchPhase !== 'idle' ? 'is-active' : ''}`}
                  />
                  {switchPhase === 'in' && (
                    <ProjectFrame
                      project={currentProject}
                      className={`modal-frame-layer is-in dir-${switchDirection}`}
                    />
                  )}
                </>
              ) : (
                <ProjectFrame project={currentProject} className="modal-frame-layer is-static" />
              )}
            </div>

            <div className="modal-counter">
              {modalIndex + 1} / {currentProjects.length}
            </div>

            <div className="modal-dots" aria-hidden="true">
              {currentProjects.map((project, index) => (
                <span
                  key={project.id}
                  className={`modal-dot ${index === modalIndex ? 'is-active' : ''}`}
                />
              ))}
            </div>
          </div>
        </>
      )}
    </section>
  );
}
